const http = require("http");
const https = require("https");
const fs = require("fs");
const path = require("path");
const { execSync } = require("child_process");

const httpRequest = (method, urlStr, body) => new Promise((resolve, reject) => {
  // Parse URL without using URL class (not in vm context)
  const m = urlStr.match(/^(https?):\/\/([^:/]+)(?::(\d+))?(\/?[^?]*)(\?.*)?$/);
  const protocol = m[1];
  const hostname = m[2];
  const port = m[3] ? parseInt(m[3]) : (protocol === "https" ? 443 : 80);
  const pathPart = (m[4] || "/") + (m[5] || "");
  const lib = protocol === "https" ? https : http;
  const options = {
    hostname: hostname,
    port: port,
    path: pathPart,
    method: method,
    headers: {}
  };
  if (body) {
    options.headers["Content-Type"] = "application/json";
    options.headers["Content-Length"] = Buffer.byteLength(body);
  }
  const req = lib.request(options, (res) => {
    let data = "";
    res.on("data", (chunk) => { data += chunk; });
    res.on("end", () => {
      try { resolve(JSON.parse(data)); }
      catch(e) { resolve(data); }
    });
  });
  req.on("error", reject);
  if (body) req.write(body);
  req.end();
});
const httpPost = (url, bodyObj) => httpRequest("POST", url, JSON.stringify(bodyObj));
const httpGet = (url) => httpRequest("GET", url, null);

const params = $("Set Global Parameters").first().json;
const comfyAPI = params.ComfyUIAPI;
const comfyInputDir = params.ComfyUIInputDir;
const comfyOutputDir = params.ComfyUIOutputDir;

const raw = $input.first().json;
const deck = (raw.data !== undefined) ? raw.data : raw;

const deckDir = (deck.Assets && deck.Assets.Directory ? deck.Assets.Directory : "D:/data/cards/Standard").replace(/\//g, path.sep);

const cardRefs = deck.Cards;
if (!cardRefs || cardRefs.length === 0) {
  throw new Error("[Generate Focus Upright Stills] No Cards found in Deck.json. Ensure the deck has a Cards array.");
}

const models = deck.Models || {};
const samplers = deck.Samplers || {};
const interpSampler = samplers.Interpolation || {};

const unetName = models.InterpolationUNet || "wan2.2_i2v_low_noise_14B_fp8_scaled.safetensors";
const clipName = models.InterpolationCLIP || "umt5_xxl_fp8_e4m3fn_scaled.safetensors";
const vaeName = models.InterpolationVAE || "wan_2.1_vae.safetensors";

const steps = interpSampler.Steps || 20;
const cfg = interpSampler.CFG || 7.0;
const denoise = interpSampler.Denoise || 1.0;
const shift = interpSampler.Shift || 1.0;
const samplerName = interpSampler.Sampler || "uni_pc_bh2";
const scheduler = interpSampler.Scheduler || "sgm_uniform";

const geom = (deck.Geometries && deck.Geometries.Animation) ? deck.Geometries.Animation : {};
const videoLength = geom.InterpolationFrames || 13;
const frameRate = geom.FrameRate || 12;
const rawW = geom.Width || 832;
const rawH = geom.Height || 480;
const vidWidth = Math.min(rawW, rawH);
const vidHeight = Math.max(rawW, rawH);

const STILL_COUNT = 7;
const FRAME_STEP = Math.round((videoLength - 1) / (STILL_COUNT - 1));

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

const results = { processed: 0, skipped: 0, failed: 0, cards: [] };
for (const cardRef of cardRefs) {
  const cardName = cardRef.Card;
  const cardFilePath = path.join(deckDir, cardRef.File.replace(/\//g, path.sep));

  let cardRaw;
  try {
    const rawText = fs.readFileSync(cardFilePath, "utf8");
    cardRaw = JSON.parse(rawText);
  } catch (e) {
    console.warn("[Generate Focus Upright Stills] Could not read/parse card file: " + cardFilePath + " error: " + e.message);
    results.failed++;
    results.cards.push({ card: cardName, status: "failed", reason: "Could not read/parse: " + e.message });
    continue;
  }

  const card = cardRaw["data.Cards"] || cardRaw;
  const cardDir = (card.Directory ? card.Directory : path.join(deckDir, "Cards")).replace(/\//g, path.sep);

  const uprightImageName = card.Assets && card.Assets.UprightImage;
  if (!uprightImageName) {
    console.warn("[Generate Focus Upright Stills] No Assets.UprightImage for card: " + cardName);
    results.skipped++;
    results.cards.push({ card: cardName, status: "skipped", reason: "No Assets.UprightImage" });
    continue;
  }

  const records = card.records || [];
  const uprightIdx = records.findIndex((r) => r.Orientation === "upright");
  if (uprightIdx === -1) {
    console.warn("[Generate Focus Upright Stills] No upright record found for card: " + cardName);
    results.skipped++;
    results.cards.push({ card: cardName, status: "skipped", reason: "No upright record" });
    continue;
  }

  const uprightRecord = records[uprightIdx];
  const cardImageName = uprightRecord.Assets && uprightRecord.Assets.CardImage;
  if (!cardImageName) {
    console.warn("[Generate Focus Upright Stills] No Assets.CardImage in upright record for card: " + cardName);
    results.skipped++;
    results.cards.push({ card: cardName, status: "skipped", reason: "No upright record Assets.CardImage" });
    continue;
  }

  const uprightImagePath = path.join(cardDir, uprightImageName);
  const cardImagePath = path.join(cardDir, cardImageName);

  if (!fs.existsSync(uprightImagePath)) {
    console.warn("[Generate Focus Upright Stills] uprightImagePath not found: " + uprightImagePath);
    results.skipped++;
    results.cards.push({ card: cardName, status: "skipped", reason: "UprightImage file not found: " + uprightImagePath });
    continue;
  }
  if (!fs.existsSync(cardImagePath)) {
    console.warn("[Generate Focus Upright Stills] cardImagePath not found: " + cardImagePath);
    results.skipped++;
    results.cards.push({ card: cardName, status: "skipped", reason: "CardImage file not found: " + cardImagePath });
    continue;
  }

  const slug = cardName.replace(/[()]/g, "").replace(/\s+/g, "_");

  const stillNames = [];
  for (let i = 0; i < STILL_COUNT; i++) {
    stillNames.push("FOCUSUPRIGHTSTILL_" + slug + "_" + i + ".png");
  }
  const stillPaths = stillNames.map((n) => path.join(cardDir, n));

  if (stillPaths.every((p) => fs.existsSync(p))) {
    console.warn("[Generate Focus Upright Stills] All stills already exist for: " + cardName + ", skipping generation.");
    if (!uprightRecord.Assets) uprightRecord.Assets = {};
    uprightRecord.Assets.FocusUpright = stillNames;
    fs.writeFileSync(cardFilePath, JSON.stringify(cardRaw, null, 2), "utf8");
    results.skipped++;
    results.cards.push({ card: cardName, status: "skipped", reason: "All stills already exist" });
    continue;
  }

  const startFilename = "focus_start_" + slug + ".png";
  const endFilename = "focus_end_" + slug + ".png";

  fs.copyFileSync(uprightImagePath, path.join(comfyInputDir, startFilename));
  fs.copyFileSync(cardImagePath, path.join(comfyInputDir, endFilename));

  const outputPrefix = "FOCUSUPRIGHT_" + slug;
  const comfyPrompt = {
    "1": {
      "class_type": "UNETLoader",
      "inputs": {
        "unet_name": unetName,
        "weight_dtype": "fp8_e4m3fn"
      }
    },
    "2": {
      "class_type": "CLIPLoader",
      "inputs": {
        "clip_name": clipName,
        "type": "wan"
      }
    },
    "3": {
      "class_type": "VAELoader",
      "inputs": {
        "vae_name": vaeName
      }
    },
    "4": {
      "class_type": "CLIPTextEncode",
      "inputs": {
        "text": "tarot card focus animation, " + cardName + " upright, smooth cinematic transition, high quality",
        "clip": ["2", 0]
      }
    },
    "5": {
      "class_type": "CLIPTextEncode",
      "inputs": {
        "text": "blurry, distorted, low quality, artifacts, watermark, text",
        "clip": ["2", 0]
      }
    },
    "6": {
      "class_type": "LoadImage",
      "inputs": {
        "image": startFilename
      }
    },
    "13": {
      "class_type": "LoadImage",
      "inputs": {
        "image": endFilename
      }
    },
    "7": {
      "class_type": "WanFirstLastFrameToVideo",
      "inputs": {
        "width": vidWidth,
        "height": vidHeight,
        "length": videoLength,
        "batch_size": 1,
        "positive": ["4", 0],
        "negative": ["5", 0],
        "vae": ["3", 0],
        "start_image": ["6", 0],
        "end_image": ["13", 0]
      }
    },
    "9": {
      "class_type": "ModelSamplingSD3",
      "inputs": {
        "model": ["1", 0],
        "shift": shift
      }
    },
    "10": {
      "class_type": "KSampler",
      "inputs": {
        "model": ["9", 0],
        "positive": ["7", 0],
        "negative": ["7", 1],
        "latent_image": ["7", 2],
        "seed": Math.floor(Math.random() * 999999999),
        "steps": steps,
        "cfg": cfg,
        "sampler_name": samplerName,
        "scheduler": scheduler,
        "denoise": denoise
      }
    },
    "11": {
      "class_type": "VAEDecode",
      "inputs": {
        "samples": ["10", 0],
        "vae": ["3", 0]
      }
    },
    "12": {
      "class_type": "VHS_VideoCombine",
      "inputs": {
        "images": ["11", 0],
        "frame_rate": frameRate,
        "loop_count": 0,
        "filename_prefix": outputPrefix,
        "format": "video/h264-mp4",
        "save_output": true,
        "pingpong": false,
        "save_metadata": false
      }
    }
  };

  let submitData;
  try {
    submitData = await httpPost(comfyAPI + "/prompt", { prompt: comfyPrompt });
  } catch (e) {
    throw new Error("[Generate Focus Upright Stills] Failed to submit to ComfyUI for card: " + cardName + " error: " + e.message);
  }

  const promptId = submitData && submitData.prompt_id;
  if (!promptId) {
    throw new Error("[Generate Focus Upright Stills] No prompt_id returned from ComfyUI for card: " + cardName);
  }

  let videoFilename = null;
  for (let attempt = 0; attempt < 180 && videoFilename === null; attempt++) {
    await sleep(5000);
    let historyData;
    try {
      historyData = await httpGet(comfyAPI + "/history/" + promptId);
    } catch (e) {
      console.warn("[Generate Focus Upright Stills] Poll error for " + cardName + ": " + e.message);
      continue;
    }
    const entry = historyData && historyData[promptId];
    if (entry && entry.outputs && entry.outputs["12"] && entry.outputs["12"].gifs && entry.outputs["12"].gifs.length > 0) {
      const gif = entry.outputs["12"].gifs[0];
      if (gif.subfolder && gif.subfolder.length > 0) {
        videoFilename = gif.subfolder + "/" + gif.filename;
      } else {
        videoFilename = gif.filename;
      }
    }
    if (entry && entry.status && entry.status.status_str === "error") {
      throw new Error("[Generate Focus Upright Stills] ComfyUI reported error for card: " + cardName + " promptId: " + promptId);
    }
  }

  if (videoFilename === null) {
    throw new Error("[Generate Focus Upright Stills] Timeout waiting for ComfyUI video for card: " + cardName + " promptId: " + promptId);
  }

  const videoPath = path.join(comfyOutputDir, videoFilename);
  const tmpPrefix = "_tmp_fus_" + slug;
  const tmpPattern = path.join(cardDir, tmpPrefix + "_%d.png");

  try {
    execSync('ffmpeg -y -i "' + videoPath + '" -vsync 0 "' + tmpPattern + '"', { encoding: "utf8" });
  } catch (e) {
    throw new Error("[Generate Focus Upright Stills] ffmpeg failed for card: " + cardName + " error: " + (e.stderr || e.message));
  }

  for (let i = 0; i < STILL_COUNT; i++) {
    const frameNum = i * FRAME_STEP + 1;
    const tmpPath = path.join(cardDir, tmpPrefix + "_" + frameNum + ".png");
    if (!fs.existsSync(tmpPath)) {
      throw new Error("[Generate Focus Upright Stills] Expected frame not found: " + tmpPath + " for card: " + cardName);
    }
    fs.renameSync(tmpPath, stillPaths[i]);
  }

  const allFiles = fs.readdirSync(cardDir);
  allFiles.filter((f) => f.startsWith(tmpPrefix)).forEach((f) => {
    fs.unlinkSync(path.join(cardDir, f));
  });

  if (!uprightRecord.Assets) uprightRecord.Assets = {};
  uprightRecord.Assets.FocusUpright = stillNames;

  fs.writeFileSync(cardFilePath, JSON.stringify(cardRaw, null, 2), "utf8");

  results.processed++;
  results.cards.push({ card: cardName, status: "generated", stills: stillNames });
}

if (results.processed === 0 && results.failed === 0) {
  console.warn("[Generate Focus Upright Stills] No cards were generated. processed=0, failed=0. skipped=" + results.skipped);
}

return [{ json: results }];
